mapper.select:
SELECT a.*
FROM sys_organization a
         INNER JOIN pr_data_grant b ON b.org_id = a.id AND b.company_id = #{companyId}
WHERE a.company_id = #{companyId}
  AND a.del_flag = '0'
  AND b.user_id = #{userId}
  AND a.level != '3'

SELECT COUNT(1)
FROM sys_organization
WHERE parent_id = #{id}
  AND company_id = #{companyId}
  AND del_flag = '0'

SELECT COUNT(1)
FROM pr_data_grant
WHERE org_id = #{id}
  AND company_id = #{companyId}
